sql:
SELECT make_name
FROM makes
ORDER BY make_name ASC;

SELECT make_name, country_of_origin
FROM makes
ORDER BY make_name ASC;

external_knowledge:
- "Top 5 vehicles" refers to the vehicles with the highest access counts; 
- "Access count" refers to the number of times a vehicle is accessed; 
- "Top users for each vehicle" refers to the users with the highest access counts for each vehicle.

sql:
SELECT DISTINCT vehicle_id AS vehicle_identifier
FROM vehicles
ORDER BY vehicle_id;
